  KEY `comment_author_email` (`comment_author_email`(10))
) ENGINE=MyISAM AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
SET FOREIGN_KEY_CHECKS=0;
INSERT INTO `pcta_comments` (`comment_ID`,`comment_post_ID`,`comment_author`,`comment_author_email`,`comment_author_url`,`comment_author_IP`,`comment_date`,`comment_date_gmt`,`comment_content`,`comment_karma`,`comment_approved`,`comment_agent`,`comment_type`,`comment_parent`,`user_id`) VALUES (2,98,'GUÍA DE VIAJE DEL TOUR A MACHUPICCHU &laquo; Peru Conexion Travel Agecy','','https://peruconexiontravel.local/guia-de-viaje-del-tour-a-machupicchu','161.35.232.89','2020-08-12 15:47:56','2020-08-12 15:47:56','[&#8230;] noviembre a marzo es la temporada de lluvias, y si quieres disfrutar al máximo tu tour Machupicchu es mejor usar ropa impermeable o un poncho de agua. De abril a octubre es la estación seca. La [&#8230;]',0,'1','The Incutio XML-RPC PHP Library -- WordPress/5.3.4','pingback',0,0),(3,92,'GUÍA DE VIAJE DEL TOUR A MACHUPICCHU &laquo; Peru Conexion Travel Agecy','','https://peruconexiontravel.local/guia-de-viaje-del-tour-a-machupicchu','161.35.232.89','2020-08-12 15:49:52','2020-08-12 15:49:52','[&#8230;] poder conocer Machupicchu, es necesario situarnos en la Ciudad del Cusco. Una vez en la ciudad del Cusco tenemos 3 formas para que viajes a [&#8230;]',0,'1','The Incutio XML-RPC PHP Library -- WordPress/5.3.4','pingback',0,0),(4,122,'TOUR MONTAÑA DE COLORES - Peru Conexion Travel Agecy Peru Conexion Travel Agecy','','https://peruconexiontravel.local/tour-montana-de-colores-2','161.35.232.89','2020-08-17 15:33:41','2020-08-17 15:33:41','[&#8230;] entrada a la Montaña Arcoíris se realiza por el pueblo de cusipata a dos horas de la ciudad luego una caminata a pie, por las [&#8230;]',0,'1','The Incutio XML-RPC PHP Library -- WordPress/5.5','pingback',0,0),(5,124,'TOURS A SALKANTAY TREKKING - Peru Conexion Travel Agecy Peru Conexion Travel Agecy','','https://peruconexiontravel.local/tour-a-salkantay-trekking','161.35.232.89','2020-08-18 22:33:22','2020-08-18 22:33:22','[&#8230;] TOURS A SALKANTAY TREKKING [&#8230;]',0,'1','The Incutio XML-RPC PHP Library -- WordPress/5.5','pingback',0,0),(6,112,'vive y disfruta. Tour machu picchu Peru Conexion Travel Agecy Peru Conexion Travel Agecy','','https://peruconexiontravel.local/tour-machu-picchu','161.35.232.89','2020-08-20 01:54:59','2020-08-20 01:54:59','[&#8230;] MACHU PICCHU [&#8230;]',0,'1','The Incutio XML-RPC PHP Library -- WordPress/5.5','pingback',0,0),(7,98,'Machu picchu vive y disfruta. Peru Conexion Travel Agecy Peru Conexion Travel Agecy','','https://peruconexiontravel.local/machu-picchu-3','161.35.232.89','2020-08-20 02:00:13','2020-08-20 02:00:13','[&#8230;] Machu Picchu En el otro barrio se ubican las casas de los nobles y el convento de las «vírgenes del sol». Entre ambos barrios hay una enorme explanada a modo de plaza. [&#8230;]',0,'1','The Incutio XML-RPC PHP Library -- WordPress/5.5','pingback',0,0),(8,122,'TOUR MONTAÑA DE LOS 7 COLORES - Peru Conexion Travel Agecy Peru Conexion Travel Agecy','','https://peruconexiontravel.local/tour-montana-de-los-7-colores','161.35.232.89','2020-10-28 16:31:34','2020-10-28 16:31:34','[&#8230;] El Tour de Montaña de 7 Colores es una de las principales actividades que están de moda en la región del Cusco y el Perú, por su belleza natural incomparable de este atractivo natural. El viaje a la Montaña de los 7 colores desde Cusco es una de las excursiones que debería de reservar si o si, no se lo puede perder. En esta excursión inolvidable, tendrá la oportunidad de explorar la popular Montaña Vinicunca, más conocida por los anglo-parlantes como el «Rainbow Mountain». [&#8230;]',0,'1','The Incutio XML-RPC PHP Library -- WordPress/5.5.1','pingback',0,0);

