ml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://es.wordpress.org/2023/05/20/wordpress-6-2-2-actualizacion-de-seguridad/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:87:\"https://es.wordpress.org/2023/05/20/wordpress-6-2-2-actualizacion-de-seguridad/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 20 May 2023 08:46:10 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:5:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:9:\"Seguridad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:3:\"6.2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:5:\"6.2.1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:5:\"6.2.2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=217204\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:399:\"¡Ya está disponible WordPress 6.2.2! La versión menor 6.2.2 soluciona 1 fallo y 1 problema de seguridad. Al ser esta una actualización de seguridad se recomienda que actualices inmediatamente tus sitios. También se han actualizado todas las versiones desde WordPress 5.9. WordPress 6.2.2 es una actualización de respuesta rápida para solucionar una regresión en la versión 6.2.1 [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5227:\"\n<h2 class=\"wp-block-heading\">¡Ya está disponible WordPress 6.2.2!</h2>\n\n\n\n<p>La versión menor 6.2.2 soluciona <a href=\"https://core.trac.wordpress.org/query?milestone=6.2.2&amp;col=id&amp;col=summary&amp;col=status&amp;col=owner&amp;col=type&amp;col=priority&amp;col=milestone&amp;order=priority\">1 fallo</a> y 1 problema de seguridad. Al ser esta una actualización de seguridad se recomienda que actualices inmediatamente tus sitios. También se han actualizado todas las versiones desde WordPress 5.9.</p>\n\n\n\n<p>WordPress 6.2.2 es una actualización de respuesta rápida para solucionar una regresión en la versión 6.2.1 y de paso parchear una vulnerabilidad detectada en la versión 6.2.1.  La siguiente versión mayor será la <a href=\"https://make.wordpress.org/core/6-3/\">versión 6.3</a>, planificada para agosto del 2023.</p>\n\n\n\n<p>Si tienes sitios con las actualizaciones automáticas en segundo plano activas el proceso de actualización empezará automáticamente.</p>\n\n\n\n<p>Puedes <a href=\"https://wordpress.org/wordpress-6.2.2.zip\">descargar WordPress 6.2.2 desde WordPress.org</a>, o visitar el escritorio de tu WordPress, hacer clic en «Actualizaciones» y luego hacer clic en «Actualizar ahora».</p>\n\n\n\n<p>Para más información sobre esta versión <a href=\"https://wordpress.org/support/wordpress-version/version-6-2-2\">visita el sitio del centro de ayuda</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Actualizaciones de seguridad incluidas en esta versión</h2>\n\n\n\n<p>Al equipo de seguridad la gustaría agradecer a las siguientes personas por haber informado con responsabilidad de las vulnerabilidades, permitiéndoles corregirlas en esta versión.</p>\n\n\n\n<ul>\n<li>Temas de bloques procesando shortcodes en datos generados por el usuario; gracias a Liam Gladdy de<a href=\"https://wpengine.com/\"> WP Engine</a> por informar de este problema.</li>\n</ul>\n\n\n\n<p>Este problema se parcheó originalmente en la versión 6.2.1, pero necesitaba más refuerzo en esta versión 6.2.2. El equipo del núcleo agradece a la comunidad por su respuesta a la versión 6.2.1 y a la colaboración a la hora de encontrar el mejor camino para una adecuada solución en la versión 6.2.2. El equipo que trabajó en la versión 6.2.2 agradecen en especial a todos su comprensión mientras trabajaban generosamente para conseguir sacar adelante esta versión lo antes posible.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Gracias a estos colaboradores de WordPress</h2>\n\n\n\n<p>Esta versión la lideró <a href=\"https://profiles.wordpress.org/desrosj/\">Jonathan Desrosiers</a>.</p>\n\n\n\n<p>WordPress 6.2.2 no habría sido posible sin las contribuciones de las siguientes personas. Su coordinación asíncrona para convertir correcciones de seguridad y mantenimiento en una versión estable es una declaración del potencial y capacidad de la comunidad WordPress.</p>\n\n\n\n<p><a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a>, <a href=\"https://profiles.wordpress.org/xknown/\">Alex Concha</a>, <a href=\"https://profiles.wordpress.org/antpb/\">Anthony Burchell</a>, <a href=\"https://profiles.wordpress.org/cbringmann/\">Chloe Bringmann</a>, <a href=\"https://profiles.wordpress.org/chriscct7/\">chriscct7</a>, <a href=\"https://profiles.wordpress.org/talldanwp/\">Daniel Richards</a>, <a href=\"https://profiles.wordpress.org/davidbaumwald/\">David Baumwald</a>, <a href=\"https://profiles.wordpress.org/ehtis/\">Ehtisham S.</a>, <a href=\"https://profiles.wordpress.org/gziolo/\">Greg Ziółkowski</a>, <a href=\"https://profiles.wordpress.org/isabel_brison/\">Isabel Brison</a>, <a href=\"https://profiles.wordpress.org/audrasjb/\">Jb Audras</a>, <a href=\"https://profiles.wordpress.org/jeffpaul/\">Jeffrey Paul</a>, <a href=\"https://profiles.wordpress.org/johnbillion/\">John Blackbourn</a>, <a href=\"https://profiles.wordpress.org/desrosj/\">Jonathan Desrosiers</a>, <a href=\"https://profiles.wordpress.org/chanthaboune/\">Josepha</a>, <a href=\"https://profiles.wordpress.org/Clorith/\">Marius L. J.</a>, <a href=\"https://profiles.wordpress.org/matveb/\">Matias Ventura</a>, <a href=\"https://profiles.wordpress.org/mikeschroder/\">Mike Schroder</a>, <a href=\"https://profiles.wordpress.org/peterwilsoncc/\">Peter Wilson</a>, <a href=\"https://profiles.wordpress.org/youknowriad/\">Riad Benguella</a>, <a href=\"https://profiles.wordpress.org/noisysocks/\">Robert Anderson</a>, <a href=\"https://profiles.wordpress.org/rmccue/\">Ryan McCue</a>, <a href=\"https://profiles.wordpress.org/Otto42/\">Samuel Wood (Otto)</a>, <a href=\"https://profiles.wordpress.org/coffee2code/\">Scott Reilly</a> y <a href=\"https://profiles.wordpress.org/timothyblynjacobs/\">Timothy Jacobs</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Cómo contribuir</h2>\n\n\n\n<p>Para involucrarte en el desarrollo del núcleo de WordPress pásate por el Trac, <a href=\"https://core.trac.wordpress.org/report/6\">elige un tique</a>, y únete a la conversación en los canales de <a href=\"https://wordpress.slack.com/archives/C02RQBWTW\">#core</a> y <a href=\"https://wordpress.slack.com/archives/C051Z1SKBDZ\">#6-3-release-leads</a>. ¿Necesitas ayuda? Echa un vistazo al <a href=\"https://make.wordpress.org/core/handbook/\">manual del contribuidor del núcleo</a>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:84:\"https://es.wordpress.org/2023/05/20/wordpress-6-2-2-actualizacion-de-seguridad/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:85:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:5:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:63:\"WordPress 6.2.1 – Actualización de mantenimiento y seguridad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:95:\"https://es.wordpress.org/2023/05/16/wordpress-6-2-1-actualizacion-de-mantenimiento-y-seguridad/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:103:\"https://es.wordpress.org/2023/05/16/wordpress-6-2-1-actualizacion-de-mantenimiento-y-seguridad/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 16 May 2023 19:05:03 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:5:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:13:\"Mantenimiento\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:9:\"Seguridad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:3:\"6.2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:5:\"6.2.1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=215382\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:421:\"¡Ya está disponible WordPress 6.2.1! Esta actualización menor incluye&#160;20 correcciones a fallos en el núcleo&#160;y&#160;10 correcciones de fallos en el editor de bloques. Puedes revisar un resumen de las novedades de mantenimiento de esta versión en el&#160;anuncio de la versión candidata a definitiva. Esta actualización también incluye varias correcciones de seguridad. Al ser una actualización [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:8181:\"\n<h2 class=\"wp-block-heading\">¡Ya está disponible WordPress 6.2.1!</h2>\n\n\n\n<p>Esta actualización menor incluye&nbsp;<a href=\"https://core.trac.wordpress.org/query?milestone=6.2.1&amp;group=component&amp;col=id&amp;col=summary&amp;col=status&amp;col=owner&amp;col=type&amp;col=priority&amp;col=milestone&amp;order=priority\">20 correcciones a fallos en el núcleo</a>&nbsp;y&nbsp;<a href=\"https://github.com/orgs/WordPress/projects/88\">10 correcciones de fallos en el editor de bloques</a>. Puedes revisar un resumen de las novedades de mantenimiento de esta versión en el&nbsp;<a href=\"https://make.wordpress.org/core/2023/05/09/wordpress-6-2-1-rc1-is-now-available/\">anuncio de la versión candidata a definitiva</a>.</p>\n\n\n\n<p>Esta actualización también incluye varias correcciones de seguridad. Al ser una actualización de seguridad te recomendamos que actualices de inmediato tus sitios. También se han actualizado todas las versiones desde WordPress 4.1.</p>\n\n\n\n<p>WordPress 6.2.1 es una versión de ciclo corto. La siguiente versión mayor será la <a href=\"https://make.wordpress.org/core/6-3/\">versión 6.3</a>, planificada para agosto del 2023.</p>\n\n\n\n<p>Si tienes sitios con las actualizaciones automáticas en segundo plano activas el proceso de actualización empezará automáticamente.</p>\n\n\n\n<p>Puedes&nbsp;<a href=\"https://wordpress.org/wordpress-6.2.1.zip\">descargar WordPress 6.2.1 desde WordPress.org</a>, o visitar el escritorio de tu WordPress, hacer clic en «Actualizaciones» y luego hacer clic en «Actualizar ahora».</p>\n\n\n\n<p>Para más información sobre esta versión&nbsp;<a href=\"https://wordpress.org/support/wordpress-version/version-6-2-1\">visita el sitio del centro de ayuda</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Actualizaciones de seguridad incluidas en esta versión</h2>\n\n\n\n<p>Al equipo de seguridad la gustaría agradecer a las siguientes personas por haber informado con responsabilidad de las vulnerabilidades, permitiéndoles corregirlas en esta versión.</p>\n\n\n\n<ul>\n<li>Temas de bloques procesando shortcodes en datos generados por el usuario; gracias a Liam Gladdy de&nbsp;<a href=\"https://wpengine.com/\">WP Engine</a>&nbsp;por informar de este problema.</li>\n\n\n\n<li>Un problema de CSRF al actualizar las miniaturas de los adjuntos; informado por&nbsp;<a href=\"https://johnblackbourn.com/\">John Blackbourn</a>&nbsp;del equipo de seguridad de WordPress</li>\n\n\n\n<li>Un fallo que permitía XSS desde el auto-descubrimiento de open embed; de lo que informó de modo independiente Jakub Żoczek de&nbsp;<a href=\"https://research.securitum.com/\">Securitum</a>&nbsp;y durante una auditoría de seguridad externa</li>\n\n\n\n<li>Omisión de saneado de KSES en atributos de bloques para usuarios con pocos privilegios; descubierto durante una auditoría de seguridad externa.</li>\n\n\n\n<li>Un problema de ruta transversal desde archivos de traducción; informado de forma independiente por Ramuel Gall <a href=\"https://research.securitum.com/\">Securitum</a>&nbsp;y durante una auditoría de seguridad externa.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Gracias a estos colaboradores de WordPress</h2>\n\n\n\n<p>Esta versión la lideraron&nbsp;<a href=\"https://profiles.wordpress.org/audrasjb\">Jb Audras</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mamaduka/\">George Mamadashvili</a>,&nbsp;<a href=\"https://profiles.wordpress.org/SergeyBiryukov\">Sergey Biryukov</a>&nbsp;y&nbsp;<a href=\"https://profiles.wordpress.org/peterwilsoncc\">Peter Wilson</a>.</p>\n\n\n\n<p>WordPress 6.2.1 no habría sido posible sin las contribuciones de las siguientes personas. Su coordinación asíncrona para convertir correcciones de seguridad y mantenimiento en una versión estable es una declaración del potencial y capacidad de la comunidad WordPress.</p>\n\n\n\n<p><a href=\"https://profiles.wordpress.org/adamsilverstein/\">Adam Silverstein</a>,&nbsp;<a href=\"https://profiles.wordpress.org/wildworks/\">Aki Hamano</a>,&nbsp;<a href=\"https://profiles.wordpress.org/amin7/\">amin</a>,&nbsp;<a href=\"https://profiles.wordpress.org/azaozz/\">Andrew Ozz</a>,&nbsp;<a href=\"https://profiles.wordpress.org/andrewserong/\">Andrew Serong</a>,&nbsp;<a href=\"https://profiles.wordpress.org/oandregal/\">André</a>,&nbsp;<a href=\"https://profiles.wordpress.org/aristath/\">Ari Stathopoulos</a>,&nbsp;<a href=\"https://profiles.wordpress.org/bph/\">Birgit Pauli-Haack</a>,&nbsp;<a href=\"https://profiles.wordpress.org/chiragrathod103/\">Chirag Rathod</a>,&nbsp;<a href=\"https://profiles.wordpress.org/costdev/\">Colin Stewart</a>,&nbsp;<a href=\"https://profiles.wordpress.org/talldanwp/\">Daniel Richards</a>,&nbsp;<a href=\"https://profiles.wordpress.org/davidbaumwald/\">David Baumwald</a>,&nbsp;<a href=\"https://profiles.wordpress.org/davidbinda/\">David Biňovec</a>,&nbsp;<a href=\"https://profiles.wordpress.org/dmsnell/\">Dennis Snell</a>,&nbsp;<a href=\"https://profiles.wordpress.org/shagors/\">devshagor</a>,&nbsp;<a href=\"https://profiles.wordpress.org/dhrumilk/\">Dhrumil Kumbhani</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ocean90/\">Dominik Schilling</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ellatrix/\">Ella</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mamaduka/\">George Mamadashvili</a>,&nbsp;<a href=\"https://profiles.wordpress.org/isabel_brison/\">Isabel Brison</a>,&nbsp;<a href=\"https://profiles.wordpress.org/audrasjb/\">Jb Audras</a>,&nbsp;<a href=\"https://profiles.wordpress.org/joedolson/\">Joe Dolson</a>,&nbsp;<a href=\"https://profiles.wordpress.org/joen/\">Joen A.</a>,&nbsp;<a href=\"https://profiles.wordpress.org/johnbillion/\">John Blackbourn</a>,&nbsp;<a href=\"https://profiles.wordpress.org/desrosj/\">Jonathan Desrosiers</a>,&nbsp;<a href=\"https://profiles.wordpress.org/juanmaguitar/\">JuanMa Garrido</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jrf/\">Juliette Reinders Folmer</a>,&nbsp;<a href=\"https://profiles.wordpress.org/kevin940726/\">Kai Hao</a>,&nbsp;<a href=\"https://profiles.wordpress.org/trepmal/\">Kailey (trepmal)</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mdxfr/\">Marc</a>,&nbsp;<a href=\"https://profiles.wordpress.org/marineevain/\">Marine EVAIN</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mattwiebe/\">Matt Wiebe</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mukesh27/\">Mukesh Panchal</a>,&nbsp;<a href=\"https://profiles.wordpress.org/nendeb55/\">nendeb</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ndiego/\">Nick Diego</a>,&nbsp;<a href=\"https://profiles.wordpress.org/nickpap/\">nickpap</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ntsekouras/\">Nik Tsekouras</a>,&nbsp;<a href=\"https://profiles.wordpress.org/pavanpatil1/\">Pavan Patil</a>,&nbsp;<a href=\"https://profiles.wordpress.org/peterwilsoncc/\">Peter Wilson</a>,&nbsp;<a href=\"https://profiles.wordpress.org/pouicpouic/\">pouicpouic</a>,&nbsp;<a href=\"https://profiles.wordpress.org/youknowriad/\">Riad Benguella</a>,&nbsp;<a href=\"https://profiles.wordpress.org/welcher/\">Ryan Welcher</a>,&nbsp;<a href=\"https://profiles.wordpress.org/coffee2code/\">Scott Reilly</a>,&nbsp;<a href=\"https://profiles.wordpress.org/sergeybiryukov/\">Sergey Biryukov</a>,&nbsp;<a href=\"https://profiles.wordpress.org/sabernhardt/\">Stephen Bernhardt</a>,&nbsp;<a href=\"https://profiles.wordpress.org/tmatsuur/\">tmatsuur</a>,&nbsp;<a href=\"https://profiles.wordpress.org/tobiasbg/\">TobiasBg</a>,&nbsp;<a href=\"https://profiles.wordpress.org/hellofromtonya/\">Tonya Mork</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ugyensupport/\">Ugyen Dorji</a>,&nbsp;<a href=\"https://profiles.wordpress.org/westonruter/\">Weston Ruter</a> y&nbsp;<a href=\"https://profiles.wordpress.org/zieladam/\">zieladam</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Cómo contribuir</h2>\n\n\n\n<p>Para involucrarte en el desarrollo del núcleo de WordPress pásate por el Trac,&nbsp;<a href=\"https://core.trac.wordpress.org/report/6\">elige un tique</a>, y únete a la conversación en los canales de&nbsp;<a href=\"https://wordpress.slack.com/archives/C02RQBWTW\">#core</a>&nbsp;y&nbsp;<a href=\"https://wordpress.slack.com/archives/C051Z1SKBDZ\">#6-3-release-leads</a>. ¿Necesitas ayuda? Echa un vistazo al&nbsp;<a href=\"https://make.wordpress.org/core/handbook/\">manual del contribuidor del núcleo</a>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:100:\"https://es.wordpress.org/2023/05/16/wordpress-6-2-1-actualizacion-de-mantenimiento-y-seguridad/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:79:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:5:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"WordPress 6.2 Beta 1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://es.wordpress.org/2023/02/09/wordpress-6-2-beta-1/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:65:\"https://es.wordpress.org/2023/02/09/wordpress-6-2-beta-1/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 09 Feb 2023 10:09:03 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:4:\"beta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=169671\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:344:\"¡WordPress 6.2 Beta 1 está lista para descarga y pruebas! Esta versión del software WordPress está en desarrollo. Por favor, no instales, ejecutes o pruebes esta versión de WordPress en webs en producción o críticas. En su lugar, deberías probar la Beta 1 en un servidor y sitio de pruebas. Puedes probar WordPress 6.2 Beta 1 [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7814:\"\n<p>¡WordPress 6.2 Beta 1 está lista para descarga y pruebas!</p>\n\n\n\n<p><strong>Esta versión del software WordPress está en desarrollo.</strong> Por favor, no instales, ejecutes o pruebes esta versión de WordPress en webs en producción o críticas. En su lugar, deberías probar la Beta 1 en un servidor y sitio de pruebas.</p>\n\n\n\n<p>Puedes probar WordPress 6.2 Beta 1 de tres maneras:</p>\n\n\n\n<p><strong>Opción 1:</strong> Instala y activa el plugin <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> (seleccionando el canal de «Desarrollo temprano» y la opción de transmisión «Solo Beta/RC»).</p>\n\n\n\n<p><strong>Opción 2: </strong>Descarga directamente la <a href=\"https://wordpress.org/wordpress-6.2-beta1.zip\">versión Beta 1 (zip)</a>.</p>\n\n\n\n<p><strong>Opción 3:</strong> Usa el siguiente comando WP-CLI:</p>\n\n\n\n<p><code>wp core update --version=6.2-beta1</code></p>\n\n\n\n<p>El objetivo actual para la versión final es <strong>el 28 de marzo de 2023</strong>, que es dentro siete semanas.Tu ayuda con las pruebas de esta versión es vital para asegurar que todo en esta versión vaya lo mejor posible.</p>\n\n\n\n<p>Echa un vistazo al <a href=\"https://make.wordpress.org/core/6-2/\">ciclo de la versión 6.2</a>, y revisa en el <a href=\"https://make.wordpress.org/core/\">blog de Make WordPress Core</a> las <a href=\"https://make.wordpress.org/core/tag/6-2/\">entradas relacionadas con la versión 6.2</a> durante las próximas semanas para más detalles.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Cómo puedes ayudar: ¡probando!</strong></h2>\n\n\n\n<p>Probar para buscar errores es crítico para estabilizar una versión durante su desarrollo. Hacer pruebas es también un fantástico modo de contribuir. Si nunca has probado una versión beta antes <a href=\"https://make.wordpress.org/test/2022/09/21/help-test-wordpress-6-1/\">esta detallada guía</a> te orientará sobre cómo empezar.</p>\n\n\n\n<p>Si creas productos para WordPress, puede que te des cuenta de que cuánto antes pruebes esta versión con tus temas, plugins y patrones, más fácil será para ti ofrecer una experiencia fluida a tus usuarios.</p>\n\n\n\n<p>¿Quieres saber más sobre la prueba de versiones en general? Puedes seguir las <a href=\"https://make.wordpress.org/test/\">iniciativas de pruebas</a> que se hacen en el blog de Make Core. También puedes unirte al <a href=\"https://wordpress.slack.com/messages/core-test/\">canal de #core-test</a> en el <a href=\"https://wordpress.slack.com/\">espacio de trabajo en Slack de Making WordPress</a>.</p>\n\n\n\n<p>Si crees que has encontrado un problema, por favor, informa de él en el <a href=\"https://wordpress.org/support/forum/alphabeta/\">área Alpha/Beta</a> de los foros de soporte. Si te sientes cómodo escribiendo un informe de fallos reproducible, puedes <a href=\"https://core.trac.wordpress.org/newticket\">archivar uno en el trac de WordPress</a>. Ahí es donde también puedes encontrar una lista de los <a href=\"https://core.trac.wordpress.org/tickets/major\">fallos conocidos</a>.</p>\n\n\n\n<p>¿Tienes interés en las características de Gutenberg? Descubre qué se ha incluido desde WordPress 6.1 (la última versión mayor de WordPress). Descubrirás más detalles en las entradas disponibles de <em>las novedades de Gutenberg</em> de las versiones <a href=\"https://make.wordpress.org/core/2023/01/20/whats-new-in-gutenberg-15-0-18-january/\">15.0</a>, <a href=\"https://make.wordpress.org/core/2023/01/04/whats-new-in-gutenberg-14-9-4-january/\">14.9</a>, <a href=\"https://make.wordpress.org/core/2022/12/22/whats-new-in-gutenberg-14-8-21-december/\">14.8</a>, <a href=\"https://make.wordpress.org/core/2022/12/09/whats-new-in-gutenberg-14-7-7-december/\">14.7</a>, <a href=\"https://make.wordpress.org/core/2022/11/23/whats-new-in-gutenberg-14-6-23-november/\">14.6</a>, <a href=\"https://make.wordpress.org/core/2022/11/09/whats-new-in-gutenberg-14-5-9-november/\">14.5</a>, <a href=\"https://make.wordpress.org/core/2022/10/27/whats-new-in-gutenberg-14-4-26-october/\">14.4</a>, <a href=\"https://make.wordpress.org/core/2022/10/13/whats-new-in-gutenberg-14-3-12-october/\">14.3</a> y <a href=\"https://make.wordpress.org/core/2022/09/30/whats-new-in-gutenberg-14-2-28-september/\">14.2</a>.</p>\n\n\n\n<p>Esta versión contiene más de 292 mejoras y 354 correciones a fallos del editor, incluyendo más de <a href=\"https://core.trac.wordpress.org/query?status=closed&amp;milestone=6.2&amp;group=component&amp;max=500&amp;col=id&amp;col=summary&amp;col=owner&amp;col=type&amp;col=priority&amp;col=component&amp;col=version&amp;order=priority\">195 tiques en el núcleo de WordPress 6.2</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Una versión mayor para un hito mayor del proyecto</strong></h2>\n\n\n\n<p>WordPress 6.2 es una de las últimas versiones mayores planificadas de la fase 2 de la <a href=\"https://wordpress.org/about/roadmap/\">hoja de ruta del proyecto Gutenberg</a>. La plataforma ha tenido un largo camino durante los últimos años. La versión 6.2 también celebra ese progreso y mira hacia un futuro en el que la publicación tenga herramientas más potentes en tus manos. </p>\n\n\n\n<p>Siguiente parada: ¡herramientas de colaboración y más, en la <a href=\"https://wordpress.org/news/2023/01/letter-from-wordpress-executive-director-2022/\">fase 3</a>!</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Aspectos destacables</strong></h2>\n\n\n\n<p><em>¿Quieres saber qué novedades hay en la versión 6.2 de WordPress? Sigue leyendo para degustar lo que está por venir.</em></p>\n\n\n\n<ul>\n<li>¡Se quita la etiqueta de Beta—señal de que el editor del sitio es estable y listo para que cualquiera explore, cree y experimente!</li>\n\n\n\n<li>Modo sin distraccoines para. una experiencia de escritura libre y centrada.</li>\n\n\n\n<li>Una nueva interfaz del editor del sitio que muestra primero las vistas previas de tus plantillas y partes de plantilla, para que puedas elegir exactamente desde dónde quieres empezar a editar.</li>\n\n\n\n<li>Ajustes de bloque en escala, con controles de separación organizan tus opciones de estilos y ajutes de manera que encuentres fácilmente lo que necesites—y veas claramente todo lo que puede hacer un bloque </li>\n\n\n\n<li>Etiquetas con colores para ayudarte a encontrar rápidamente tus partes de plantilla y bloques reutilizables, da igual dónde mires: en la vista de lista, la barra de herramientas del bloque, incluso en el lienzo.</li>\n\n\n\n<li>Una experiencia de navegación mejorada hace que sea más sencillo crear y gestionar menús—desde la barra lateral de ajustes del bloque.</li>\n\n\n\n<li>Los patrones son más fáciles de encontrar e insertar—¡con incluso más categorías entre las que elegir, como cabeceras y pies de página! </li>\n\n\n\n<li>Un nuevo libro de estilo ofrece un único lugar en el que ver todos tus estilos de cada bloque, para un vistazo completo de los detalles de estilo de tu sitio.</li>\n\n\n\n<li>Compatibilidad de CSS personalizado para bloques específicos, o todo el sitio, para disponer de otro nivel de control sobre cómo quieres que se vean las cosas. </li>\n\n\n\n<li>La integración con Openverse te permite obtrener directamente medios con licencia abierta en tu contenido a medida que trabajas—además de un modo más rápido de insertar medios desde tu biblioteca actual.</li>\n\n\n\n<li>Los widgets se convierten en partes de plantilla cuando cambias de un tema clásico a uno de bloques—haciendo que la transición sea mucho más suave.</li>\n</ul>\n\n\n\n<p><em>Por favor, ten en cuenta que las características de esta lista podrían cambiar antes de la versión final.</em></p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Un haiku para la 6.2</strong></h2>\n\n\n\n<p>Ya la última de la fase 2<br>Que empiece la fiesta<br>WordPress cumple 20</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:62:\"https://es.wordpress.org/2023/02/09/wordpress-6-2-beta-1/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:5:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"Experiencias WordCamp Sevilla 2022\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"https://es.wordpress.org/2022/11/25/experiencias-wordcamp-sevilla-2022/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://es.wordpress.org/2022/11/25/experiencias-wordcamp-sevilla-2022/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 25 Nov 2022 09:46:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=140543\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:323:\"El pasado 5 y 6 de noviembre tuvo lugar WordCamp Sevilla 2022. La idea con la que se concibió este evento fue acercar a personas que no conocían la comunidad WordPress y para los que era su primera WordCamp. Para ir preparando el terreno con antelación, en las meetups mensuales se fue realizando un itinerario [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"Jorge\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:3294:\"\n<p>El pasado 5 y 6 de noviembre tuvo lugar WordCamp Sevilla 2022.</p>\n\n\n\n<p>La idea con la que se concibió este evento fue acercar a personas que no conocían la comunidad WordPress y para los que era su primera WordCamp.</p>\n\n\n\n<p>Para ir preparando el terreno con antelación, en las meetups mensuales se fue realizando un itinerario paso a paso explicando desde qué es un dominio hasta crear distintos tipos de web.</p>\n\n\n\n<p>Nuevas personas se fueron sumando a estas reuniones hasta llegar al evento WordCamp Sevilla 2022.</p>\n\n\n\n<p>Con el fin de acercar estos eventos oficiales de WordPress a personas sin conocimientos y así evitar el pensamiento común de que son eventos orientados únicamente a usuarios avanzados y profesionales, se seleccionaron charlas en las que se explicaba cada una de las fases de creación de un proyecto web.</p>\n\n\n\n<p>Así pudimos disfrutar de las charlas <a href=\"https://sevilla.wordcamp.org/2022/session/la-puerta-de-entrada-a-wordpress/\">la puerta de entrada a WordPress</a>,  <a href=\"https://sevilla.wordcamp.org/2022/session/para-que-utilizar-wordpress/\">para qué utilizar WordPress</a>, <a href=\"https://sevilla.wordcamp.org/2022/session/paso-a-paso-de-creacion-de-una-web/\">paso a paso de creación de una web</a> y <a href=\"https://sevilla.wordcamp.org/2022/session/dar-a-conocer-tu-proyecto/\">dar a conocer tu proyecto</a>. </p>\n\n\n\n<h2 class=\"wp-block-heading\">Mesa de expertos: lo que se pensó y lo que terminó siendo…para mejor</h2>\n\n\n\n<p>Si bien la <a href=\"https://sevilla.wordcamp.org/2022/session/sala-de-expertos/\">mesa de expertos</a> no es un concepto nuevo, al estar formada por usuarios avanzados de WordPress a los que hacerle preguntas para solucionar dudas, no es cómo se pensó sino lo que pasó.</p>\n\n\n\n<p>La idea inicial eran cuatro personas con experiencia en WordPress, y que contestaran las preguntas de los asistentes que se fueran acercando a las mesas.</p>\n\n\n\n<p>En un primer momento se pensaron tres mesas, para principiantes, avanzados y comunidad.</p>\n\n\n\n<p>Por iniciativa de los propios participantes de las mesas se pasó a sentarnos todos en círculo en los que cualquiera hacía la pregunta que quisiera y quien sabía responder lo hacía dejando paso a otras respuestas o formas de hacer.</p>\n\n\n\n<p>El resultado fue que se habló de comunidad, seguridad, temas, plugins, WPO, tiendas online…y los 10 del principio luego fueron 20, 35…hasta que se acabó el tiempo. Si no seguiríamos allí.</p>\n\n\n\n<p>Sin duda es algo a tener en cuenta para replicar en próximas ediciones.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Algunos datos de WordCamp Sevilla 2022</h2>\n\n\n\n<p>En cuanto a algunos datos interesantes, tenemos que el 50% de los asistentes eran la primera vez que asistían a una WordCamp, siendo una gran parte de ellos estudiantes, algo inédito hasta la fecha. </p>\n\n\n\n<p>Además también se consiguió un 33% de asistencia femenina, lo cual también supera la media de los eventos celebrados hasta la fecha en Sevilla.</p>\n\n\n\n<p>Siempre por supuesto con cosas que mejorar, pero sin duda objetivo cumplido por parte de la organización. </p>\n\n\n\n<p>Gente nueva, con ideas nuevas y ganas de hacer cosas.</p>\n\n\n\n<p>Ya queda menos para la próxima WordCamp Sevilla. <strong>¡Nos vemos allí!</strong></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"https://es.wordpress.org/2022/11/25/experiencias-wordcamp-sevilla-2022/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:5:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:22:\"State of the Word 2022\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"https://es.wordpress.org/2022/11/24/state-of-the-word-2022/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:67:\"https://es.wordpress.org/2022/11/24/state-of-the-word-2022/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 24 Nov 2022 08:16:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"General\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=142962\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:174:\"¡State of the Word 2022 ya está en el calendario! Únete a los líderes y colaboradores del proyecto #WordPress para el evento anual en Nueva York o online. #StateOfTheWord\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"anagavilan\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:3060:\"\n<p id=\"tw-target-text\">¡Hola, WordPresser! </p>\n\n\n\n<p id=\"tw-target-text\"><a href=\"https://calendar.google.com/calendar/u/0/r/eventedit?text=State+of+the+Word+2022&amp;dates=20221215T180000Z/20221215T193000Z&amp;details=State+of+the+Word+is+the+annual+keynote+address+delivered+by+the+WordPress+project%E2%80%99s+co-founder%2C+Matt+Mullenweg.+Every+year%2C+the+event+shares+reflections+on+the+project%E2%80%99s+progress+and+the+future+of+open+source.+Expect+this+and+more+in+this+year%E2%80%99s+edition.%0A%0AState+of+the+Word+will+be+live+streamed+from+New+York+City,+and+is+free+for+all+to+watch.%0A%0Ahttps://wordpress.org/news/2022/11/state-of-the-word-2022/\">Marca tu calendario</a>; <strong>¡Ya casi es la hora del State of the Word(Estado de la Palabra) 2022!</strong> </p>\n\n\n\n<p id=\"tw-target-text\">State of the Word es el discurso de apertura anual pronunciado por el cofundador del proyecto WordPress, <a href=\"https://ma.tt/\">Matt Mullenweg</a>. Cada año, el evento comparte reflexiones sobre el progreso del proyecto y el futuro del código abierto. </p>\n\n\n\n<p id=\"tw-target-text\">El evento de este año tendrá lugar en la ciudad de Nueva York y se transmitirá en vivo a través de varias plataformas de redes sociales de WordPress.org. </p>\n\n\n\n<p id=\"tw-target-text\">Únete a Matt mientras brinda una retrospectiva de 2022, los últimos lanzamientos de WordPress, los avances del Editor del sitio y el regreso a los eventos en persona en todo el mundo, entre otros temas. </p>\n\n\n\n<p id=\"tw-target-text\"><strong>Cuándo: </strong>15 de diciembre de 2022, de 1 p. m. a 2:30 p. m. EST (18–19:30 UTC) </p>\n\n\n\n<p id=\"tw-target-text\"><strong>Cómo: </strong>la transmisión en vivo se integrará en esta publicación y estará disponible a través del canal de YouTube de WordPress. </p>\n\n\n\n<p id=\"tw-target-text\">Estás en Nueva York o cerca y ¿te gustaría unirte al público en persona? <a href=\"https://wordcampcentral.survey.fm/request-a-seat-sotw-2022\">Solicita un asiento completando esta encuesta.</a> </p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"tw-target-text\">¿Tienes alguna pregunta para Matt? </h2>\n\n\n\n<p id=\"tw-target-text\">State of the Word incluirá una sesión de preguntas y respuestas. Si deseas participar, puedes enviar tu pregunta con anticipación a <strong>ask-matt@wordcamp.org</strong> o preguntar durante el evento en el chat en vivo en YouTube. </p>\n\n\n\n<p id=\"tw-target-text\">Dado el volumen de preguntas que generalmente se envían, es posible que no sea posible responderlas todas en la sesión de preguntas y respuestas en vivo. Se publicará una publicación de seguimiento después del State of the Word para responder a aquellos que no dio tiempo. </p>\n\n\n\n<p id=\"tw-target-text\">¿Es la primera vez que asiste al Estado de la Palabra? Echa un vistazo a las <a href=\"https://wordpress.tv/tag/state-of-the-word/\">grabaciones de años anteriores en WordPress.tv</a> para tener una idea del evento. </p>\n\n\n\n<p id=\"tw-target-text\"><strong>¡Nos vemos en persona o en línea el 15 de diciembre!</strong></p>\n\n\n\n<p></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"https://es.wordpress.org/2022/11/24/state-of-the-word-2022/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:82:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:5:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:51:\"WordPress 6.1.1 – Actualización de mantenimiento\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://es.wordpress.org/2022/11/15/wordpress-6-1-1-actualizacion-de-mantenimiento/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:91:\"https://es.wordpress.org/2022/11/15/wordpress-6-1-1-actualizacion-de-mantenimiento/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 15 Nov 2022 20:02:41 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:4:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:13:\"Mantenimiento\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:3:\"6.1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:5:\"6.1.1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=139504\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:438:\"Ya está disponible WordPress 6.1.1 Esta versión menor incluye&#160;29 correcciones a fallos en el núcleo&#160;y&#160;21 correcciones de fallos&#160;del editor de bloques. WordPress 6.1.1 es una actualización de mantenimiento de ciclo corto. Puedes er un resumen de las actualizacionesclave de esta versión leyendo el anuncio de la&#160;versión RC1. La siguiente actualización mayor será la&#160;versión 6.2, planificada [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:10684:\"\n<p><strong>Ya está disponible WordPress 6.1.1</strong></p>\n\n\n\n<p>Esta versión menor incluye&nbsp;<a href=\"https://core.trac.wordpress.org/query?milestone=6.1.1&amp;group=component&amp;col=id&amp;col=summary&amp;col=status&amp;col=owner&amp;col=type&amp;col=priority&amp;col=milestone&amp;order=priority\">29 correcciones a fallos en el núcleo</a>&nbsp;y&nbsp;<a href=\"https://github.com/WordPress/gutenberg/compare/ca07aa8354a1131dbabcc36dfcaf70e0c0891f54...6566f5fe9ece6ad5ae550349d3b1f0944a011040\">21 correcciones de fallos</a>&nbsp;del editor de bloques. WordPress 6.1.1 es una actualización de mantenimiento de ciclo corto. Puedes er un resumen de las actualizacionesclave de esta versión leyendo el anuncio de la&nbsp;<a href=\"https://make.wordpress.org/core/2022/11/11/wordpress-6-1-1-rc1-is-now-available/\">versión RC1</a>.</p>\n\n\n\n<p>La siguiente actualización mayor será la&nbsp;<a href=\"https://make.wordpress.org/core/6-2/\">versión 6.2</a>, planificada para 2023.</p>\n\n\n\n<p>Si tienes sitios con las actualizaciones automáticas en segundo plano activas el proceso de actualización empezará automáticamente.</p>\n\n\n\n<p>Puedes <a href=\"https://es.wordpress.org/latest-es_ES.zip\">descargar WordPress 6.1.1 desde WordPress.org</a>, o visitar tu escritorio de WordPress, hacer clic en «Actualizaciones» y luego hacer clic en «Actualizar ahora».</p>\n\n\n\n<p>Para más información echa un vistazo a la&nbsp;<a href=\"https://wordpress.org/support/wordpress-version/version-6-1-1/\">página de documentación de la versión 6.1.1 en HelpHub</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Gracias a estos colaboradores de WordPress</h2>\n\n\n\n<p>La versión WordPress 6.1.1 la lideraron&nbsp;<a href=\"https://profiles.wordpress.org/desrosj/\">@desrosj</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mamaduka/\">@mamaduka</a> y&nbsp;<a href=\"https://profiles.wordpress.org/jeffpaul/\">@jeffpaul</a>.</p>\n\n\n\n<p>WordPress 6.1.1 no habría sido posible sin las contribuciones de más de 105 personas. Su coordinación asíncrona a la hora de convertir varias mejoras y correcciones en una versión estable es una declaración del potencial y capacidad de la comunidad WordPress.  </p>\n\n\n\n<p><a href=\"https://profiles.wordpress.org/10upsimon/\">10upsimon</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a>,&nbsp;<a href=\"https://profiles.wordpress.org/aaronrobertshaw/\">Aaron Robertshaw</a>,&nbsp;<a href=\"https://profiles.wordpress.org/adamsilverstein/\">Adam Silverstein</a>,&nbsp;<a href=\"https://profiles.wordpress.org/wildworks/\">Aki Hamano</a>,&nbsp;<a href=\"https://profiles.wordpress.org/alexstine/\">alexstine</a>,&nbsp;<a href=\"https://profiles.wordpress.org/andraganescu/\">Andrei Draganescu</a>,&nbsp;<a href=\"https://profiles.wordpress.org/azaozz/\">Andrew Ozz</a>,&nbsp;<a href=\"https://profiles.wordpress.org/andrewserong/\">Andrew Serong</a>,&nbsp;<a href=\"https://profiles.wordpress.org/oandregal/\">Andre</a>,&nbsp;<a href=\"https://profiles.wordpress.org/afragen/\">Andy Fragen</a>,&nbsp;<a href=\"https://profiles.wordpress.org/aristath/\">Ari Stathopoulos</a>,&nbsp;<a href=\"https://profiles.wordpress.org/azurseisme/\">azurseisme</a>,&nbsp;<a href=\"https://profiles.wordpress.org/scruffian/\">Ben Dwyer</a>,&nbsp;<a href=\"https://profiles.wordpress.org/bernhard-reiter/\">Bernie Reiter</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mxbclang/\">Bethany Chobanian Lang</a>,&nbsp;<a href=\"https://profiles.wordpress.org/bph/\">Birgit Pauli-Haack</a>,&nbsp;<a href=\"https://profiles.wordpress.org/bjorn2404/\">bjorn2404</a>,&nbsp;<a href=\"https://profiles.wordpress.org/cbravobernal/\">Carlos Bravo</a>,&nbsp;<a href=\"https://profiles.wordpress.org/poena/\">Carolina Nymark</a>,&nbsp;<a href=\"https://profiles.wordpress.org/claytoncollie/\">Clayton Collie</a>,&nbsp;<a href=\"https://profiles.wordpress.org/codesdnc/\">codesdnc</a>,&nbsp;<a href=\"https://profiles.wordpress.org/costdev/\">Colin Stewart</a>,&nbsp;<a href=\"https://profiles.wordpress.org/talldanwp/\">Daniel Richards</a>,&nbsp;<a href=\"https://profiles.wordpress.org/davidbaumwald/\">David Baumwald</a>,&nbsp;<a href=\"https://profiles.wordpress.org/get_dave/\">David Smith</a>,&nbsp;<a href=\"https://profiles.wordpress.org/davidvongries/\">David Vongries</a>,&nbsp;<a href=\"https://profiles.wordpress.org/dilipbheda/\">Dilip Bheda</a>,&nbsp;<a href=\"https://profiles.wordpress.org/dd32/\">Dion Hulse</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ocean90/\">Dominik Schilling</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ellatrix/\">Ella</a>,&nbsp;<a href=\"https://profiles.wordpress.org/manuilov/\">Eugene M</a>,&nbsp;<a href=\"https://profiles.wordpress.org/flixos90/\">Felix Arntz</a>,&nbsp;<a href=\"https://profiles.wordpress.org/fpodhorsky/\">fpodhorsky</a>,&nbsp;<a href=\"https://profiles.wordpress.org/franz00/\">franzaurus</a>,&nbsp;<a href=\"https://profiles.wordpress.org/gamecreature/\">gamecreature</a>,&nbsp;<a href=\"https://profiles.wordpress.org/pento/\">Gary Pendergast</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mamaduka/\">George Mamadashvili</a>,&nbsp;<a href=\"https://profiles.wordpress.org/gisgeo/\">gisgeo</a>,&nbsp;<a href=\"https://profiles.wordpress.org/glendaviesnz/\">glendaviesnz</a>,&nbsp;<a href=\"https://profiles.wordpress.org/innovext/\">Innovext</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ironprogrammer/\">ironprogrammer</a>,&nbsp;<a href=\"https://profiles.wordpress.org/isabel_brison/\">Isabel Brison</a>,&nbsp;<a href=\"https://profiles.wordpress.org/outrankjames/\">James</a>,&nbsp;<a href=\"https://profiles.wordpress.org/janthiel/\">Jan Thiel</a>,&nbsp;<a href=\"https://profiles.wordpress.org/carazo/\">Javier Carazo</a>,&nbsp;<a href=\"https://profiles.wordpress.org/audrasjb/\">Jb Audras</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jchambo/\">jchambo</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jeffpaul/\">jeffpaul</a>,&nbsp;<a href=\"https://profiles.wordpress.org/joelmadigan/\">joelmadigan</a>,&nbsp;<a href=\"https://profiles.wordpress.org/joen/\">Joen A.</a>,&nbsp;<a href=\"https://profiles.wordpress.org/johnbillion/\">John Blackbourn</a>,&nbsp;<a href=\"https://profiles.wordpress.org/johnwatkins0/\">John Watkins</a>,&nbsp;<a href=\"https://profiles.wordpress.org/desrosj/\">Jonathan Desrosiers</a>,&nbsp;<a href=\"https://profiles.wordpress.org/spacedmonkey/\">Jonny Harris</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jsh4/\">jsh4</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jrf/\">Juliette Reinders Folmer</a>,&nbsp;<a href=\"https://profiles.wordpress.org/kadamwhite/\">K. Adam White</a>,&nbsp;<a href=\"https://profiles.wordpress.org/kacper3355/\">kacper3355</a>,&nbsp;<a href=\"https://profiles.wordpress.org/kevin940726/\">Kai Hao</a>,&nbsp;<a href=\"https://profiles.wordpress.org/obenland/\">Konstantin Obenland</a>,&nbsp;<a href=\"https://profiles.wordpress.org/konyoldeath/\">konyoldeath</a>,&nbsp;<a href=\"https://profiles.wordpress.org/larsmqller/\">larsmqller</a>,&nbsp;<a href=\"https://profiles.wordpress.org/0mirka00/\">Lena Morita</a>,&nbsp;<a href=\"https://profiles.wordpress.org/leonidasmilossis/\">Leo Milo</a>,&nbsp;<a href=\"https://profiles.wordpress.org/lozula/\">lozula</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mciampini/\">Marco Ciampini</a>,&nbsp;<a href=\"https://profiles.wordpress.org/tyxla/\">Marin Atanasov</a>,&nbsp;<a href=\"https://profiles.wordpress.org/clorith/\">Marius L. J.</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mattkeys/\">Matt Keys</a>,&nbsp;<a href=\"https://profiles.wordpress.org/czapla/\">Michal Czaplinski</a>,&nbsp;<a href=\"https://profiles.wordpress.org/miguelaxcar/\">Miguel Axcar</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mcsf/\">Miguel Fonseca</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mukesh27/\">Mukesh Panchal</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mw108/\">mw108</a>,&nbsp;<a href=\"https://profiles.wordpress.org/namithjawahar/\">Namith Jawahar</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ndiego/\">Nick Diego</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ntsekouras/\">Nik Tsekouras</a>,&nbsp;<a href=\"https://profiles.wordpress.org/nithins53/\">Nithin SreeRaj</a>,&nbsp;<a href=\"https://profiles.wordpress.org/nuvopoint/\">nuvoPoint</a>,&nbsp;<a href=\"https://profiles.wordpress.org/oakesjosh/\">oakesjosh</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ockham/\">ockham</a>,&nbsp;<a href=\"https://profiles.wordpress.org/webmandesign/\">Oliver Juhas</a>,&nbsp;<a href=\"https://profiles.wordpress.org/swissspidy/\">Pascal Birchler</a>,&nbsp;<a href=\"https://profiles.wordpress.org/pbiron/\">Paul Biron</a>,&nbsp;<a href=\"https://profiles.wordpress.org/peterwilsoncc/\">Peter Wilson</a>,&nbsp;<a href=\"https://profiles.wordpress.org/petitphp/\">petitphp</a>,&nbsp;<a href=\"https://profiles.wordpress.org/pkolenbr/\">pkolenbr</a>,&nbsp;<a href=\"https://profiles.wordpress.org/pypwalters/\">pypwalters</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ramonopoly/\">ramonopoly</a>,&nbsp;<a href=\"https://profiles.wordpress.org/youknowriad/\">Riad Benguella</a>,&nbsp;<a href=\"https://profiles.wordpress.org/rjasdfiii/\">rjasdfiii</a>,&nbsp;<a href=\"https://profiles.wordpress.org/noisysocks/\">Robert Anderson</a>,&nbsp;<a href=\"https://profiles.wordpress.org/rodricus/\">rodricus</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ryankienstra/\">Ryan Kienstra</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mikachan/\">Sarah Norris</a>,&nbsp;<a href=\"https://profiles.wordpress.org/sergeybiryukov/\">Sergey Biryukov</a>,&nbsp;<a href=\"https://profiles.wordpress.org/stentibbing/\">stentibbing</a>,&nbsp;<a href=\"https://profiles.wordpress.org/sabernhardt/\">Stephen Bernhardt</a>,&nbsp;<a href=\"https://profiles.wordpress.org/subrataemfluence/\">Subrata Sarkar</a>,&nbsp;<a href=\"https://profiles.wordpress.org/cybr/\">Sybre Waaijer</a>,&nbsp;<a href=\"https://profiles.wordpress.org/sippis/\">Timi Wahalahti</a>,&nbsp;<a href=\"https://profiles.wordpress.org/timothyblynjacobs/\">Timothy Jacobs</a>,&nbsp;<a href=\"https://profiles.wordpress.org/hellofromtonya/\">Tonya Mork</a>,&nbsp;<a href=\"https://profiles.wordpress.org/zodiac1978/\">Torsten Landsiedel</a> y&nbsp;<a href=\"https://profiles.wordpress.org/vtad/\">vtad</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Cómo contribuir</h2>\n\n\n\n<p>Para involucrarte en el desarrollo del núcleo WordPress, pásate por el Trac,&nbsp;<a href=\"https://core.trac.wordpress.org/report/6\">elige un tique</a> y únete a la converssación en los canales de&nbsp;<a href=\"https://wordpress.slack.com/archives/C02RQBWTW\">#core</a>&nbsp;y&nbsp;<a href=\"https://wordpress.slack.com/archives/C03LZ88NX6G\">#6-1-release-leads</a>. ¿Necesitas ayuda? Revisa el&nbsp;<a href=\"https://make.wordpress.org/core/handbook/\">manual de contribuidor al núcleo</a>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"https://es.wordpress.org/2022/11/15/wordpress-6-1-1-actualizacion-de-mantenimiento/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:5:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:40:\"Dicen que hay una primera vez para todo.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"https://es.wordpress.org/2022/11/13/dicen-que-hay-una-primera-vez-para-todo/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:84:\"https://es.wordpress.org/2022/11/13/dicen-que-hay-una-primera-vez-para-todo/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 13 Nov 2022 19:27:48 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=138626\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:369:\"Redactado por Erika Orlando En este caso, mi primera WordCamp (con coletilla): Mi primera WordCamp y además, en el equipo de organización. No puedo estar más encantada con esta oportunidad. Seré sincera, me postulé para voluntaria: cargar mesas, sillas, cajas, etc. Lo que hiciera falta. Pero recibí una llamada de Érica Aguado. Esta conversación vino [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Alvaro Torres\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7873:\"\n<p>Redactado por <strong>Erika Orlando</strong></p>\n\n\n\n<p>En este caso, mi primera WordCamp (con coletilla): <strong>Mi primera WordCamp y además, en el equipo de organización.</strong></p>\n\n\n\n<p>No puedo estar más encantada con esta oportunidad.</p>\n\n\n\n<p>Seré sincera, me postulé para voluntaria: cargar mesas, sillas, cajas, etc. Lo que hiciera falta.</p>\n\n\n\n<p>Pero recibí una llamada de Érica Aguado. Esta conversación vino siendo así:</p>\n\n\n\n<p><em>Érica: Te he visto en la lista de voluntarios y quería preguntarte si querrías ayudarnos con las Redes Sociales desde ya.</em></p>\n\n\n\n<p>Pensé en “salir corriendo”. No me llevo muy bien con las redes, me cuesta mucho trabajo crear contenido, nunca creo encontrar las palabras adecuadas para agradecer mensajes y, a veces, me pierdo en el mundo paralelo de las notificaciones, pero bueno, para todo hay una primera vez y me apetecía mucho aportar mi granito de arena en la comunidad.</p>\n\n\n\n<p><em>Yo: Claro Érica, no te preocupes, yo me hago cargo.</em></p>\n\n\n\n<p>Empieza la <em>Falla</em> y la lluvia de accesos, mensajes, reuniones…</p>\n\n\n\n<p><em>¡Wow! Todo esto, ¿os lo habéis comido los 6 solos?</em></p>\n\n\n\n<p>A la semana siguiente, no sé en qué momento, me vuelve a llamar Érica, que han pensado que mejor me “Digievolucionan”, que las redes dan mucha guerra y que quieren que me una al equipo. ¡¡Ay, la leche!!</p>\n\n\n\n<p>Ahora sí. Estoy entusiasmada, eufórica, pletórica y, sobre todo, muy asustada. No podía imaginar que organizar un evento de tal magnitud significara tanto sacrificio, en este caso, sacrificio que he visto en todo el equipo. Estrés, pérdida de horas de sueño, debates de una duración superior a lo que había visto hasta ahora y un gran esfuerzo por parte de todos para conseguir conciliar nuestras vidas, nuestros trabajos y la organización de un evento de casi 400 personas de manera totalmente altruista, pero que tenía que ser “una gran <em>Falla</em>”.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Mi experiencia como coordinadora de Redes Sociales en la WordCamp Valencia 2022</strong></h2>\n\n\n\n<p>Mi parte de la falla comienza su festejo cuando cojo el relevo de IG, Twitter y… ¡Ostras! No tenemos LinkedIn, que no cunda el pánico. Todo tiene solución.</p>\n\n\n\n<p>El mismo día, me presentan a un equipo de mujeres que han sido parte importantísima en la comunicación vía RRSS de esta WordCampVLC:</p>\n\n\n\n<p>Anabella que desde Argentina era nuestro “turno de noche” y en 4 días llevó la cuenta de LinkedIn a la altura de IG, publicando todo aquello que faltaba. También decir que una vez llegada a Valencia ha sido implacable en redes durante toda la WordCamp. Pudisteis verla sacando fotos con la 360°, con el móvil y porque no le dejamos, si no le quita la cámara a Nilo.</p>\n\n\n\n<p>Alba, que con su experiencia nos hizo la vida más fácil con una serie de Copy´s para automatizar algunas cosillas. Su dedicación al trabajo es inspiradora ¿Visteis una mujer pegada al móvil? Era ella, seguro.</p>\n\n\n\n<p>Carla Patricia, no había conocido jamás a nadie con tanta ganas de trabajar y de aportar su parte en algo en lo que no va a participar presencialmente. Desde Las Palmas de Gran Canaria nos ha brindado todo su apoyo y cariño, además, durante el streaming se encargó de moderar y hacernos llegar los mensajitos que iba dejando la gente.</p>\n\n\n\n<p>Y contando con este pedazo de equipo diréis “<em>Erika (con k), ¿Y tú qué hiciste?</em>”</p>\n\n\n\n<p>Yo me encargué de coordinar con el equipo de diseño todas las creatividades, aquí Patricia era mi salvación, dar apoyo en las diferentes redes sociales, contestar mensajes y compartir todo lo que ponentes, patrocinadores y asistentes nos hacían llegar. Y desde aquí me gustaría dar las gracias a todas y a todos por colaborar en la comunicación de este evento.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>El Contributor Day, un antes y un después</strong></h2>\n\n\n\n<p>Una cosa es conocer la comunidad WordPress en las MeetUp que se realizan de manera regular, en las que aprendes muchísimo y se crean vínculos y sinergias muy chulas, y otra es ver, estar y participar en un Contributor Day, o Community Day como lo llamamos en WordCamp Valencia.</p>\n\n\n\n<p>Mi primer Contributor Day, obvio, ha sido mi primera WordCamp. No tuve manera de participar activamente en ninguna mesa, lo intenté en un par, pero las responsabilidades se me amontonaban y había que cumplir. No, esto no es del todo cierto. No participé en ninguna mesa, pero estuve en todas. ¿Cómo hice esto?</p>\n\n\n\n<p>Solo este día se acreditaron 104 personas, y solo el 30% conocían la comunidad, esto propició que el otro 70% estuvieran muy atentos en la presentación de la jornada y les surgieran pequeñas dudas, y una cosa que me encantó es que se acercaran a preguntar para resolverlas. Carne de comunidad.</p>\n\n\n\n<p>Así llevé a más de 20 asistentes a la mesa que me habían dicho que les llamaba la atención. Tengo un caso muy presente, el de Alfonso.</p>\n\n\n\n<p>Alfonso no conocía la comunidad, llevaba tres semanas trabajando con WordPress y se había enterado de la WordCamp por casualidad. Tuve oportunidad de hablar un poquito con él durante la acreditación y otro poquito después de la presentación, cuando se acercó a preguntarme en qué mesa le recomendaba sentarse.</p>\n\n\n\n<p>Sabía que la mesa que presidían Juan y Rocío le vendría muy bien, la mesa de Comunidad. ¿Sabéis qué pasó?</p>\n\n\n\n<p>Al final de la jornada pude hablar de nuevo con Alfonso y me anunció repleto de energía que iba a reabrir la MeetUp de Sagunto. No me lo podía creer. De no conocer nada a comprometerse de lleno con la comunidad.</p>\n\n\n\n<p>¡Qué importante es el Contributor Day!</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Día de ponencias</strong></h2>\n\n\n\n<p>Creo que este día fue uno de los más complicados para la organización, no el día en sí, pero sí su organización. Sobre todo la elección de las ponencias. Se presentaron más de 60, pero solo podíamos escoger 18. No fue nada fácil. Se buscó un equilibrio en la temática y creo que lo conseguimos.</p>\n\n\n\n<p>Mi más sincero agradecimiento a aquellos y aquellas que presentaron su propuesta y, por supuesto, a los que finalmente nos entregaron tanto contenido de valor desde la tarima.Si quieres verlas están todas las grabaciones del día en<a href=\"https://wordpress.tv/event/wordcamp-valencia-2022/\" target=\"_blank\" rel=\"noreferrer noopener\"> WordPress.Tv</a> o en la página oficial de la<a href=\"https://valencia.wordcamp.org/2022/programa/\" target=\"_blank\" rel=\"noreferrer noopener\"> WordCamp Valencia 2022</a>, clicando en el título de cada ponencia.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Y con esto me despido</strong></h2>\n\n\n\n<p>Tengo una pequeña sensación de vacío después de la WordCamp. Esto me pasa cuando trabajo en algo en lo que creo pero llega a su fin. Aunque en este caso solo es un freno, en WordPress Valencia seguimos con las MeetUp y ya tenemos el foco puesto en WordCamp Valencia 2023, así que ¡atentos!.</p>\n\n\n\n<p>No me puedo despedir sin agradecer a todos los voluntarios su dedicación y compromiso, pero sobre todo, su alegría durante todo el evento (a pesar del cansancio). No tengo palabras.</p>\n\n\n\n<p>Gracias también a todos los patrocinadores. Conocer en persona a los representantes de las empresas con las que trabajamos habitualmente siempre es una grata experiencia. Además, ¡trajeron un montón de regalitos chulos!</p>\n\n\n\n<p>Pero sobre todo, gracias a todo el equipo, Érica Aguado, Patricia Navarro, Javier Hernández, Luis Francisco Bautista, Ricardo Vilar y Julián Ruiz. ¿Qué decir de ellos que no haya dicho ya? No me quedan palabras para expresar lo bien que me he sentido trabajando con ellos.</p>\n\n\n\n<p>¡Gracias!</p>\n\n\n\n<p></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:81:\"https://es.wordpress.org/2022/11/13/dicen-que-hay-una-primera-vez-para-todo/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:5:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"WordPress 6.1 «Misha»\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"https://es.wordpress.org/2022/11/04/wordpress-6-1-misha/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"https://es.wordpress.org/2022/11/04/wordpress-6-1-misha/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 04 Nov 2022 16:30:37 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=134148\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:347:\"Te damos la bienvenida a «Misha» Saluda a WordPress 6.1 «Misha», inspirado en la vida y obra del pianista de jazz soviético-noruego Mikhail «Misha» Alperin. Misha introdujo el trabajo de los conjuntos de jazz en la URSS y en todo el mundo. También es célebre como miembro fundador del Moscow Art Trio. «Misha» perfecciona aún [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:82086:\"\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2022/11/wp-61-misha.jpg\"><img decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://es.wordpress.org/files/2022/11/wp-61-misha.jpg\" alt=\"\" class=\"wp-image-134149\" srcset=\"https://es.wordpress.org/files/2022/11/wp-61-misha.jpg 1024w, https://es.wordpress.org/files/2022/11/wp-61-misha-300x200.jpg 300w, https://es.wordpress.org/files/2022/11/wp-61-misha-768x512.jpg 768w\" sizes=\"(max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Te damos la bienvenida a «Misha»</h2>\n\n\n\n<p>Saluda a WordPress 6.1 «Misha», inspirado en la vida y obra del pianista de jazz soviético-noruego <a href=\"https://en.wikipedia.org/wiki/Mikhail_Alperin\" target=\"_blank\" rel=\"noreferrer noopener\">Mikhail «Misha» Alperin</a>. </p>\n\n\n\n<p>Misha introdujo el trabajo de los conjuntos de jazz en la URSS y en todo el mundo. También es célebre como miembro fundador del <a href=\"https://en.wikipedia.org/wiki/Moscow_Art_Trio\" target=\"_blank\" rel=\"noreferrer noopener\">Moscow Art Trio</a>.</p>\n\n\n\n<p>«Misha» perfecciona aún más la experiencia de creación web. </p>\n\n\n\n<p>En WordPress 6.1 interactuarás con mejoras que siguen haciendo más intuitiva la creación de sitios, al tiempo que amplían tus límites creativos más que nunca. </p>\n\n\n\n<p>No te olvides de disfrutar del piano de jazz de Misha mientras disfrutas de todo lo que WordPress 6.1 tiene que ofrecer.</p>\n\n\n\n<p>La tercera gran versión de 2022 ya está aquí. <a href=\"https://es.wordpress.org/latest-es_ES.zip\">Descárgala ahora</a>. En el momento de este lanzamiento, WordPress está detrás del <a rel=\"noreferrer noopener\" href=\"https://w3techs.com/technologies/overview/content_management\" target=\"_blank\">43%</a> de las webs de todo el mundo.</p>\n\n\n\n<p>Los propietarios y administradores de sitios deberían actualizarse hoy para aprovechar al máximo las numerosas mejoras de estabilidad, rendimiento y usabilidad. </p>\n\n\n\n<p>Además, los creadores de contenido de WordPress disfrutarán de un conjunto de nuevas características orientadas a mejorar las experiencias de escritura y diseño.</p>\n\n\n\n<blockquote class=\"wp-block-quote\">\n<p>Esta versión incluye las características que más han entusiasmado a la comunidad de WordPress desde el inicio de este proyecto. Las mejoras adicionales y las mejoras en el editor dan a los propietarios de sitios más control y una personalización más fácil, a la vez que ofrecen una experiencia más cohesionada a los usuarios. La versión incluye muchas mejoras centradas en la escritura, porque si estás dando voz a los sin voz tienes que centrarte en la gente que escribe el texto.</p>\n\n\n\n<p>Algunas de mis mejoras favoritas son la posibilidad mejorada de seleccionar párrafos parciales en un bloque; los ajustes para mantener la vista de lista abierta por defecto; y el atajo de teclado para añadir enlaces internos expandidos a todos los bloques.</p>\n<cite>Josepha Haden Chomphosy, Directora Ejecutiva</cite></blockquote>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://es.wordpress.org/latest-es_ES.zip\">Descarga WordPress 6.1</a></div>\n</div>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<h2 class=\"wp-block-heading\">Qué hay en el interior</h2>\n\n\n\n<h3 class=\"wp-block-heading\">Twenty Twenty-Three:<br>Un nuevo tema por defecto con 10 variaciones de estilo distintas</h3>\n\n\n\n<p>Basándose en los elementos fundamentales de las versiones 5.9 y 6.0 para los temas de bloques y las variaciones de estilo, el nuevo tema por defecto, Twenty Twenty-Three, incluye&nbsp;<a rel=\"noreferrer noopener\" href=\"https://make.wordpress.org/design/2022/09/07/tt3-default-theme-announcing-style-variation-selections/\" target=\"_blank\">10 estilos diferentes</a>&nbsp;y está «<a rel=\"noreferrer noopener\" href=\"https://make.wordpress.org/themes/handbook/review/accessibility/\" target=\"_blank\">listo para accesibilidad</a>».</p>\n\n\n\n<p>Estos estilos intencionadamente únicos garantizan que los usuarios puedan aplicar un aspecto diferente a su sitio con un solo clic, todo dentro de un mismo tema.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2022/11/variaciones-de-estilo.jpg\"><img decoding=\"async\" width=\"1024\" height=\"601\" src=\"https://es.wordpress.org/files/2022/11/variaciones-de-estilo.jpg\" alt=\"\" class=\"wp-image-134150\" srcset=\"https://es.wordpress.org/files/2022/11/variaciones-de-estilo.jpg 1024w, https://es.wordpress.org/files/2022/11/variaciones-de-estilo-300x176.jpg 300w, https://es.wordpress.org/files/2022/11/variaciones-de-estilo-768x451.jpg 768w\" sizes=\"(max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Nuevas plantillas para una mejor experiencia para el creador</h3>\n\n\n\n<p>Unas plantillas nuevas y más depuradas ofrecen ahora a los creadores de sitios un mayor control sobre la creación de los mismos. </p>\n\n\n\n<p>En este conjunto de nuevas plantillas, encuentra una plantilla personalizada para entradas y páginas en el editor de sitios. </p>\n\n\n\n<p>Crea y edita partes de plantilla como cabeceras y pies de página más rápidamente con una nueva herramienta de búsqueda y reemplazo y visualiza fácilmente tu nuevo sitio.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2022/11/plantillas.jpg\"><img decoding=\"async\" width=\"1024\" height=\"601\" src=\"https://es.wordpress.org/files/2022/11/plantillas.jpg\" alt=\"\" class=\"wp-image-134151\" srcset=\"https://es.wordpress.org/files/2022/11/plantillas.jpg 1024w, https://es.wordpress.org/files/2022/11/plantillas-300x176.jpg 300w, https://es.wordpress.org/files/2022/11/plantillas-768x451.jpg 768w\" sizes=\"(max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Herramientas de diseño para una mayor consistencia y control</h3>\n\n\n\n<p>Las cuidadosas actualizaciones de los controles de los elementos de diseño y los bloques hacen que el diseño y la construcción de tu nuevo sitio sean una experiencia más coherente, completa e intuitiva.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2022/11/herramientas-diseno.jpg\"><img decoding=\"async\" loading=\"lazy\" width=\"1024\" height=\"601\" src=\"https://es.wordpress.org/files/2022/11/herramientas-diseno.jpg\" alt=\"\" class=\"wp-image-134152\" srcset=\"https://es.wordpress.org/files/2022/11/herramientas-diseno.jpg 1024w, https://es.wordpress.org/files/2022/11/herramientas-diseno-300x176.jpg 300w, https://es.wordpress.org/files/2022/11/herramientas-diseno-768x451.jpg 768w\" sizes=\"(max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Gestiona los menús con facilidad</h3>\n\n\n\n<p>Las nuevas opciones de recuperación en el bloque de navegación permiten editar el menú abierto, sin necesidad de buscarlo.</p>\n\n\n\n<p>Además, los controles para elegir y trabajar en los menús tienen su propio lugar en los ajustes del bloque.</p>\n\n\n\n<p>El sistema de menús para móviles también se actualiza con nuevas características, incluyendo diferentes opciones de iconos, para que el menú sea tuyo.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2022/11/navegacion-1.jpg\"><img decoding=\"async\" loading=\"lazy\" width=\"1024\" height=\"601\" src=\"https://es.wordpress.org/files/2022/11/navegacion-1.jpg\" alt=\"\" class=\"wp-image-134153\" srcset=\"https://es.wordpress.org/files/2022/11/navegacion-1.jpg 1024w, https://es.wordpress.org/files/2022/11/navegacion-1-300x176.jpg 300w, https://es.wordpress.org/files/2022/11/navegacion-1-768x451.jpg 768w\" sizes=\"(max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Visualización de diseños y ajustes de documentos más limpios</h3>\n\n\n\n<p>Visualiza y gestiona los ajustes de las entradas y las páginas con una pantalla mejor organizada que mejora el uso de características como el selector de plantillas y el programador.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2022/11/ajustes-documento.jpg\"><img decoding=\"async\" loading=\"lazy\" width=\"1024\" height=\"601\" src=\"https://es.wordpress.org/files/2022/11/ajustes-documento.jpg\" alt=\"\" class=\"wp-image-134154\" srcset=\"https://es.wordpress.org/files/2022/11/ajustes-documento.jpg 1024w, https://es.wordpress.org/files/2022/11/ajustes-documento-300x176.jpg 300w, https://es.wordpress.org/files/2022/11/ajustes-documento-768x451.jpg 768w\" sizes=\"(max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Ajuste de bloqueo con un solo clic para todos los bloques interiores</h3>\n\n\n\n<p>Al bloquear bloques, un nuevo conmutador te permite aplicar tus ajustes de bloqueo a todos los bloques de un bloque contenedor, como los bloques de grupo, fondo y columna.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2022/11/bloquear-bloques.jpg\"><img decoding=\"async\" loading=\"lazy\" width=\"1024\" height=\"601\" src=\"https://es.wordpress.org/files/2022/11/bloquear-bloques.jpg\" alt=\"\" class=\"wp-image-134155\" srcset=\"https://es.wordpress.org/files/2022/11/bloquear-bloques.jpg 1024w, https://es.wordpress.org/files/2022/11/bloquear-bloques-300x176.jpg 300w, https://es.wordpress.org/files/2022/11/bloquear-bloques-768x451.jpg 768w\" sizes=\"(max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Mejora de los marcadores de posición de los bloques</h3>\n\n\n\n<p>Varios bloques tienen marcadores de posición mejorados que reflejan opciones de personalización para ayudarte a diseñar tu sitio y su contenido.</p>\n\n\n\n<p>Por ejemplo, el marcador de posición del bloque de imagen muestra bordes personalizados y filtros de duotono incluso antes de seleccionar una imagen.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2022/11/marcadores-bloques.jpg\"><img decoding=\"async\" loading=\"lazy\" width=\"538\" height=\"400\" src=\"https://es.wordpress.org/files/2022/11/marcadores-bloques.jpg\" alt=\"\" class=\"wp-image-134156\" srcset=\"https://es.wordpress.org/files/2022/11/marcadores-bloques.jpg 538w, https://es.wordpress.org/files/2022/11/marcadores-bloques-300x223.jpg 300w\" sizes=\"(max-width: 538px) 100vw, 538px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Crea listas y citas más enriquecidas con bloques interiores</h3>\n\n\n\n<p>Los bloques de lista y cita ahora admiten bloques interiores, lo que permite composiciones más flexibles y enriquecidas, como añadir encabezados dentro de los bloques de cita.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2022/11/listas.jpg\"><img decoding=\"async\" loading=\"lazy\" width=\"538\" height=\"400\" src=\"https://es.wordpress.org/files/2022/11/listas.jpg\" alt=\"\" class=\"wp-image-134157\" srcset=\"https://es.wordpress.org/files/2022/11/listas.jpg 538w, https://es.wordpress.org/files/2022/11/listas-300x223.jpg 300w\" sizes=\"(max-width: 538px) 100vw, 538px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Textos más adaptables con tipografía fluida</h3>\n\n\n\n<p>La <a href=\"https://make.wordpress.org/core/2022/08/04/whats-new-in-gutenberg-13-8-3-august/#fluid-typography-support\" target=\"_blank\" rel=\"noreferrer noopener\">tipografía fluida</a> te permite definir tamaños de fuente que se adaptan para facilitar la lectura en cualquier tamaño de pantalla.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2022/11/tipografia-fluida.jpg\"><img decoding=\"async\" loading=\"lazy\" width=\"538\" height=\"400\" src=\"https://es.wordpress.org/files/2022/11/tipografia-fluida.jpg\" alt=\"\" class=\"wp-image-134158\" srcset=\"https://es.wordpress.org/files/2022/11/tipografia-fluida.jpg 538w, https://es.wordpress.org/files/2022/11/tipografia-fluida-300x223.jpg 300w\" sizes=\"(max-width: 538px) 100vw, 538px\" /></a></figure>\n\n\n\n<h3 class=\"wp-block-heading\">Añade patrones de inicio a cualquier tipo de contenido</h3>\n\n\n\n<p>En WordPress 6.0, cuando creabas una nueva página podrías ver patrones sugeridos para que no tuvieses que empezar con una página en blanco. </p>\n\n\n\n<p>En la versión 6.1 también verás una ventana emergente de patrones de inicio cuando crees una nueva instancia de cualquier tipo de contenido.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Encuentra temas de bloques más rápido</h3>\n\n\n\n<p>El directorio de temas tiene&nbsp;<a href=\"https://wordpress.org/themes/tags/full-site-editing/\" target=\"_blank\" rel=\"noreferrer noopener\">un filtro para temas de bloques</a>, y una vista previa de patrones que, cuando se revisan distintos temas y patrones, ofrece una mejor idea de cómo se vería el tema.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Guarda tus ajustes del editor para más tarde</h3>\n\n\n\n<p>Los ajustes del editor del sitio ahora son&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/10/changes-to-block-editor-preferences-in-wordpress-6-1/\" target=\"_blank\" rel=\"noreferrer noopener\">persistentes para cada usuario</a>. Esto significa que tus ajustes ahora serán consistentes en los distintos navegadores y dispositivos.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Un sistema de estilos optimizado</h3>\n\n\n\n<p>Las reglas CSS de los márgenes, rellenos, tipografías, colores y bordes del&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/10/block-styles-generation-style-engine/\" target=\"_blank\" rel=\"noreferrer noopener\">motor de estilos</a>&nbsp;ahora están en un único lugar, reduciendo así el tiempo empleado en tareas específicas de diseño y ayudando a generar nombres de clases semánticos.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Actualización de la interfaz de opciones y características</h3>\n\n\n\n<p>Las actualizaciones incluyen&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/10/styling-elements-in-block-themes/\" target=\"_blank\" rel=\"noreferrer noopener\">elementos de estilo</a>&nbsp;como botones, citas y enlaces de manera global; controla el estado de hover, active y focus de los enlaces usando theme.json (no disponible todavía para controlarlo en la interfaz); y personalizar la compatibilidad con el contorno de bloques y elementos, entre otras características.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Evolución continua de las opciones de diseño</h3>\n\n\n\n<p>Las dimensiones por defecto del contenido facilitadas por los temas pueden ahora anularse en la barra lateral de estilos, lo que ofrece a los creadores de sitios un mejor control sobre el contenido de ancho completo. Los desarrolladores tienen&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/10/updated-editor-layout-support-in-6-1-after-refactor/\" target=\"_blank\" rel=\"noreferrer noopener\">un control muy preciso sobre estos controles</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Partes de plantillas de bloques en temas clásicos</h3>\n\n\n\n<p><a href=\"https://make.wordpress.org/core/2022/10/04/block-based-template-parts-in-traditional-themes/\" target=\"_blank\" rel=\"noreferrer noopener\">Las partes de plantilla con bloques pueden ahora definirse en los temas clásicos</a>&nbsp;añadiendo los archivos HTML apropiados al directorio&nbsp;<code>parts</code>&nbsp;en la carpeta raíz del tema.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Ampliada la compatibilidad de bloques de consulta de contenidos</h3>\n\n\n\n<p><a href=\"https://make.wordpress.org/core/2022/10/10/extending-the-query-loop-block/\" target=\"_blank\" rel=\"noreferrer noopener\">Nuevos filtros</a>&nbsp;que permiten que las variaciones del bloque de consultas admitan consultas de variaciones más potentes y opciones avanzadas de filtrado jerárquico de tipos de contenido.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Filtros para todos tus estilos</h3>\n\n\n\n<p><a href=\"https://make.wordpress.org/core/2022/10/10/filters-for-theme-json-data/\">Saca partido a los filtros</a>&nbsp;de la barra lateral de estilos para controlar los ajustes en los cuatro niveles de tu sitio: núcleo, tema, usuario o bloque, de menos a más específico.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Preajustes de espaciado para un diseño más rápido y consistente</h3>\n\n\n\n<p>Ahorra tiempo y ayuda a evitar tener que escribir código de valores en el tema con&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/07/introduction-of-presets-across-padding-margin-and-block-gap/\" target=\"_blank\" rel=\"noreferrer noopener\">valores de margen y relleno preestablecidos para múltiples bloques</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Edición solo de contenido en bloques contenedores</h3>\n\n\n\n<p>Gracias a los&nbsp;<a href=\"https://make.wordpress.org/core/2022/10/11/content-locking-features-and-updates/\" target=\"_blank\" rel=\"noreferrer noopener\">ajustes de edición solo de contenido</a>&nbsp;se pueden bloquear diseños dentro de bloques contenedores. En un bloque solo de contenido, sus hijos son invisibles en la vista de lista y no se pueden editar en absoluto. Así controlas el diseño mientras que tus escritores pueden centrarse en el contenido.</p>\n\n\n\n<p>Combínalo con las opciones de bloqueo de bloques para tener aún más control avanzado de tus bloques.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Otras notas de interés</h3>\n\n\n\n<ul>\n<li>WordPress 6.1 incluye una nueva característica de tiempo de lectura que muestra a los autores de contenidos los valores aproximados de tiempo de lectura para páginas, entradas y tipos de contenido personalizados.</li>\n\n\n\n<li>La descripción corta del sitio está vacía por defecto en los sitios nuevos, pero puede modificarse en los ajustes generales.</li>\n\n\n\n<li>Un nuevo diseño emergente ofrece un efecto de desenfoque del fondo, lo que facilita la concentración en la tarea que se está realizando.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Mejoras de accesibilidad de WordPress 6.1</h2>\n\n\n\n<p>La accesibilidad es una parte integral de la misión de WordPress de fomentar una comunidad inclusiva y apoyar a los usuarios de todo tipo en todo el mundo.</p>\n\n\n\n<p>Con este objetivo, WordPress 6.1 incluye casi 60 novedades centradas específicamente en la mejora de la accesibilidad de la plataforma. </p>\n\n\n\n<p><a rel=\"noreferrer noopener\" href=\"https://make.wordpress.org/core/2022/10/11/wordpress-6-1-accessibility-improvements/\" target=\"_blank\">Lee estas actualizaciones</a> para saber más sobre las continuas iniciativas destinadas a mejorar la accesibilidad.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Mejoras de rendimiento en WordPress 6.1</h2>\n\n\n\n<p>WordPress 6.1 resuelve más de 25 tiques dedicados a aumentar el rendimiento con mejoras para cada tipo de sitio. Se puede encontrar un desglose completo en la <a href=\"https://make.wordpress.org/core/2022/10/11/performance-field-guide-for-wordpress-6-1/\" target=\"_blank\" rel=\"noreferrer noopener\">guía de campo de rendimiento</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Aprende más sobre WordPress 6.1</h2>\n\n\n\n<p>¡Ve WordPress 6.1 en acción!&nbsp;<a href=\"https://mantenimientoa.sg-host.com/breikidans/wp-admin/about.php#\" target=\"_blank\" rel=\"noreferrer noopener\">Mira un breve vídeo de resumen</a>&nbsp;que destaca algunas de las principales características estrenadas en WordPress 6.1.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" class=\"youtube-player\" width=\"612\" height=\"345\" src=\"https://www.youtube.com/embed/1w9oywSa6Hw?version=3&#038;rel=1&#038;showsearch=0&#038;showinfo=1&#038;iv_load_policy=1&#038;fs=1&#038;hl=es-ES&#038;autohide=2&#038;wmode=transparent\" allowfullscreen=\"true\" style=\"border:0;\" sandbox=\"allow-scripts allow-same-origin allow-popups allow-presentation\"></iframe>\n</div></figure>\n\n\n\n<p>Busca en&nbsp;<a href=\"https://learn.wordpress.org/\" target=\"_blank\" rel=\"noreferrer noopener\">learn.wordpress.org</a>&nbsp;tutoriales en vídeo, talleres online, cursos y planes de lecciones para organizadores de Meetup, incluidas las nuevas características de WordPress.</p>\n\n\n\n<p>Los desarrolladores pueden explorar la <a href=\"https://make.wordpress.org/core/2022/10/12/wordpress-6-1-field-guide/\" target=\"_blank\" rel=\"noreferrer noopener\">guía de campo de WordPress 6.1</a>, completa con notas detalladas para desarrolladores que le ayudarán a construir y ampliar WordPress.</p>\n\n\n\n<p>Lee las <a href=\"https://wordpress.org/support/wordpress-version/version-6-1\" target=\"_blank\" rel=\"noreferrer noopener\">notas de la versión de WordPress 6.1</a> para obtener más información sobre las mejoras incluidas y los problemas solucionados, información sobre la instalación, notas y recursos para desarrolladores, colaboradores de la versión y la lista de cambios en los archivos de esta versión.</p>\n\n\n\n<h2 class=\"wp-block-heading\">El equipo de la versión 6.1 de WordPress</h2>\n\n\n\n<p>El grupo que se menciona a continuación apoyó incansablemente el lanzamiento, desde su concepción hasta la fecha de lanzamiento, y más allá:</p>\n\n\n\n<ul>\n<li>Líder de la versión:&nbsp;<a href=\"https://profiles.wordpress.org/matt/\">Matt Mullenweg</a>&nbsp;</li>\n\n\n\n<li>Coordinadores de la versión:&nbsp;<a href=\"https://profiles.wordpress.org/priethor/\">Héctor Prieto</a>&nbsp;y&nbsp;<a href=\"https://profiles.wordpress.org/desrosj/\">Jonathan Desrosiers</a>&nbsp;</li>\n\n\n\n<li>Co-líderes técnicos del núcleo:&nbsp;<a href=\"https://profiles.wordpress.org/mikeschroder/\">Mike Schroder</a>,&nbsp;<a href=\"https://profiles.wordpress.org/davidbaumwald/\">David Baumwald</a> y&nbsp;<a href=\"https://profiles.wordpress.org/jeffpaul/\">Jeff Paul</a></li>\n\n\n\n<li>Co-líderes técnicos del editor:&nbsp;<a href=\"https://profiles.wordpress.org/czapla/\">Michal Czaplinski</a>,&nbsp;<a href=\"https://profiles.wordpress.org/bernhard-reiter/\">Bernie Reiter</a> y&nbsp;<a href=\"https://profiles.wordpress.org/cbravobernal/\">Carlos Bravo</a></li>\n\n\n\n<li>Co-líderes de triage del núcleo:&nbsp;<a href=\"https://profiles.wordpress.org/audrasjb/\">JB Audras</a>&nbsp;y&nbsp;<a href=\"https://profiles.wordpress.org/chaion07/\">Ahmed Chaion</a></li>\n\n\n\n<li>Co-líderes de triage del editor:&nbsp;<a href=\"https://profiles.wordpress.org/ndiego/\">Nick Diego</a>&nbsp;y&nbsp;<a href=\"https://profiles.wordpress.org/annezazu/\">Anne McCarthy</a></li>\n\n\n\n<li>Co-líderes de documentación:&nbsp;<a href=\"https://profiles.wordpress.org/bph/\">Birgit Pauli-Haack</a>,&nbsp;<a href=\"https://profiles.wordpress.org/milana_cap/\">Milana Cap</a> y&nbsp;<a href=\"https://profiles.wordpress.org/femkreations/\">Femy Praseeth</a></li>\n\n\n\n<li>Co-líderes de marketing y comunicaciones:&nbsp;<a href=\"https://profiles.wordpress.org/jpantani/\">Jonathan Pantani</a>&nbsp;and&nbsp;<a href=\"https://profiles.wordpress.org/dansoschin/\">Dan Soschin</a></li>\n\n\n\n<li>Líder de las pruebas:&nbsp;<a href=\"https://profiles.wordpress.org/ironprogrammer/\">Brian Alexander</a></li>\n\n\n\n<li>Líder de diseño:&nbsp;<a href=\"https://profiles.wordpress.org/richtabor/\">Rich Tabor</a></li>\n\n\n\n<li>Co-líderes del tema por defecto :&nbsp;<a href=\"https://profiles.wordpress.org/beafialho/\">Beatriz Fialho</a>&nbsp;y&nbsp;<a href=\"https://profiles.wordpress.org/mikachan/\">Sarah Norris</a></li>\n</ul>\n\n\n\n<blockquote class=\"wp-block-quote\">\n<p>Gracias a todos los colaboradores que han dedicado tiempo y energía para ofrecer la mejor experiencia de WordPress a todos.</p>\n<cite>Josepha Haden Chomphosy, Directora Ejecutiva</cite></blockquote>\n\n\n\n<p class=\"is-style-short-text has-light-grey-2-color has-blueberry-1-background-color has-text-color has-background has-link-color h