por el Ministerio de Agricultura y autoridades del Parque Nacional del Manu (SERNANP). La Zona Cultural del Manu cuenta con un bosque nublado que en la actualidad es una de las zonas del mundo donde la fauna silvestre todavía vive en abundancia en su habita natural donde existen 8.000 especies de plantas, más de 400 especies de aves y 10 especies de mamíferos han sido identificadas en el bosque nublado del Manu. '),(1953,230,'_descripcion','field_5e629af417021'),(1954,230,'galeria','a:4:{i:0;s:3:\"228\";i:1;s:3:\"229\";i:2;s:3:\"224\";i:3;s:3:\"223\";}'),(1955,230,'_galeria','field_5e629b2417022'),(1956,230,'precio','20'),(1957,230,'_precio','field_5e62a061a38d2'),(1958,230,'testimonio','1'),(1959,230,'_testimonio','field_5e62c2b421f51'),(1960,231,'_wp_attached_file','2020/03/lagosandoval3.jpg'),(1961,231,'_wp_attachment_metadata','a:5:{s:5:\"width\";i:876;s:6:\"height\";i:493;s:4:\"file\";s:25:\"2020/03/lagosandoval3.jpg\";s:5:\"sizes\";a:4:{s:6:\"medium\";a:4:{s:4:\"file\";s:25:\"lagosandoval3-300x169.jpg\";s:5:\"width\";i:300;s:6:\"height\";i:169;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:9:\"thumbnail\";a:4:{s:4:\"file\";s:25:\"lagosandoval3-150x150.jpg\";s:5:\"width\";i:150;s:6:\"height\";i:150;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:12:\"medium_large\";a:4:{s:4:\"file\";s:25:\"lagosandoval3-768x432.jpg\";s:5:\"width\";i:768;s:6:\"height\";i:432;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:9:\"destacada\";a:4:{s:4:\"file\";s:25:\"lagosandoval3-388x304.jpg\";s:5:\"width\";i:388;s:6:\"height\";i:304;s:9:\"mime-type\";s:10:\"image/jpeg\";}}s:10:\"image_meta\";a:12:{s:8:\"aperture\";s:1:\"0\";s:6:\"credit\";s:0:\"\";s:6:\"camera\";s:0:\"\";s:7:\"caption\";s:0:\"\";s:17:\"created_timestamp\";s:1:\"0\";s:9:\"copyright\";s:0:\"\";s:12:\"focal_length\";s:1:\"0\";s:3:\"iso\";s:1:\"0\";s:13:\"shutter_speed\";s:1:\"0\";s:5:\"title\";s:0:\"\";s:11:\"orientation\";s:1:\"0\";s:8:\"keywords\";a:0:{}}}'),(1962,232,'_wp_attached_file','2020/03/lagosandoval4.jpg'),(1963,232,'_wp_atta