a9f17020'),(2474,327,'descripcion','Nuestro Bungee Jumping es el más alto en Latinoamérica, esta actividad se realiza en nuestro parque ubicado en el distrito de Poroy a 15 minutos de la ciudad, usted estará suspendido desde un elevador  a 120mts de altura.'),(2475,327,'_descripcion','field_5e629af417021'),(2476,327,'galeria','a:3:{i:0;s:3:\"324\";i:1;s:3:\"325\";i:2;s:3:\"326\";}'),(2477,327,'_galeria','field_5e629b2417022'),(2478,327,'precio','20'),(2479,327,'_precio','field_5e62a061a38d2'),(2480,327,'testimonio','1'),(2481,327,'_testimonio','field_5e62c2b421f51'),(2482,328,'_wp_attached_file','2020/03/maras.jpg'),(2483,328,'_wp_attachment_metadata','a:5:{s:5:\"width\";i:876;s:6:\"height\";i:493;s:4:\"file\";s:17:\"2020/03/maras.jpg\";s:5:\"sizes\";a:4:{s:6:\"medium\";a:4:{s:4:\"file\";s:17:\"maras-300x169.jpg\";s:5:\"width\";i:300;s:6:\"height\";i:169;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:9:\"thumbnail\";a:4:{s:4:\"file\";s:17:\"maras-150x150.jpg\";s:5:\"width\";i:150;s:6:\"height\";i:150;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:12:\"medium_large\";a:4:{s:4:\"file\";s:17:\"maras-768x432.jpg\";s:5:\"width\";i:768;s:6:\"height\";i:432;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:9:\"destacada\";a:4:{s:4:\"file\";s:17:\"maras-388x304.jpg\";s:5:\"width\";i:388;s:6:\"height\";i:304;s:9:\"mime-type\";s:10:\"image/jpeg\";}}s:10:\"image_meta\";a:12:{s:8:\"aperture\";s:1:\"0\";s:6:\"credit\";s:0:\"\";s:6:\"camera\";s:0:\"\";s:7:\"caption\";s:0:\"\";s:17:\"created_timestamp\";s:1:\"0\";s:9:\"copyright\";s:0:\"\";s:12:\"focal_length\";s:1:\"0\";s:3:\"iso\";s:1:\"0\";s:13:\"shutter_speed\";s:1:\"0\";s:5:\"title\";s:0:\"\";s:11:\"orientation\";s:1:\"0\";s:8:\"keywords\";a:0:{}}}'),(2484,329,'_wp_attached_file','2020/03/salineras4.jpg'),(2485,329,'_wp_attachment_metadata','a:5:{s:5:\"width\";i:876;s:6:\"height\";i:493;s:4:\"file\";s:22:\"2020/03/salineras4.jpg\";s:5:\"sizes\";a:4:{s:6:\"medium\";a:4:{s:4:\"file\";s:22:\"salineras4-300x169.jpg\";s:5:\"width\";i:300;s:6:\"height\