INSERT INTO `pcta_postmeta` (`meta_id`,`post_id`,`meta_key`,`meta_value`) VALUES (5285,682,'duracion','2 Dias / 1 Noche'),(5286,682,'_duracion','field_5e629a9f17020'),(5287,682,'descripcion','El camino Inca corto combina hermosos paisajes de montaña y vistas panorámicas increíbles, exuberante bosque nublado, una selva subtropical del espléndido entorno natural, con el magnífico trabajo de los Incas como una mezcla excepcional de pavimento de piedras colocados sobre el camino, la agricultura, terrazas, fuentes de agua, túneles y sitios arqueológicos sorprendentes como la famosa Puerta del Sol y de la puesta de sol sobre Machu Picchu. Esta caminata es ideal para aquellos que tienen tiempo limitado y aquellos que quieran tener una caminata fácil de lograr.'),(5288,682,'_descripcion','field_5e629af417021'),(5289,682,'galeria','a:4:{i:0;s:3:\"269\";i:1;s:3:\"270\";i:2;s:3:\"271\";i:3;s:3:\"416\";}'),(5290,682,'_galeria','field_5e629b2417022'),(5291,682,'precio','20'),(5292,682,'_precio','field_5e62a061a38d2'),(5293,682,'testimonio','1'),(5294,682,'_testimonio','field_5e62c2b421f51'),(5295,682,'incluye_iconos','a:7:{i:0;s:21:\"Opción 1: Transporte\";i:1;s:16:\"Opción 2: Hotel\";i:2;s:19:\"Opción 3: Desayuno\";i:3;s:15:\"Opción 4: Guia\";i:4;s:18:\"Opción 5: Tickets\";i:5;s:15:\"Opción 6: Tren\";i:6;s:19:\"Opción 7: Caminata\";}'),(5296,682,'_incluye_iconos','field_645c284de7fdd'),(5297,112,'inline_featured_image','0'),(5298,684,'_edit_lock','1683835173:1'),(5299,684,'_edit_last','1'),(5302,684,'_thumbnail_id','293'),(5303,684,'_wp_page_template','default'),(5304,684,'inline_featured_image','0'),(5306,689,'_edit_lock','1683837132:1'),(5307,689,'_edit_last','1'),(5309,692,'_edit_lock','1684357334:1'),(5310,692,'_edit_last','1'),(5311,692,'_wp_page_template','default'),(5312,692,'inline_featured_image','0'),(5313,694,'_edit_lock','1684949162:1'),(5314,694,'_edit_last','1'),(5315,694,'_thumbnail_id','559'),(5316,694,'_wp_page_template','single-blog.php'),(5320,694,'inline_fea