ingle-blog.php'),(5415,739,'_wp_old_slug','tour-valle-sagrado-de-los-incas'),(5416,739,'inline_featured_image','0'),(5419,66,'_yoast_wpseo_content_score','90'),(5420,66,'_yoast_wpseo_estimated-reading-time-minutes','1'),(5421,66,'_yoast_wpseo_wordproof_timestamp',''),(5422,66,'incluye_iconos',''),(5423,66,'_incluye_iconos','field_645c284de7fdd'),(5424,743,'duracion','Todo el Dia'),(5425,743,'_duracion','field_5e629a9f17020'),(5426,743,'descripcion','<a href=\"http://peruconexiontravel.local\">Arequipa,</a> también conocido como: ciudad blanca, <a href=\"http://peruconexiontravel.local/\">la ciudad heroica del caudillo</a>, etc. es la segunda ciudad más grande del Perú, ubicada en la provincia y departamento homónimos.\r\nVisitaremos la plaza de armas, una de las más bellas del Perú, la Iglesia jesuita de la Compañía de Jesús, que en su bella fachada anuncia la denominada arquitectura mestiza, sus claustros y cúpula, la casona Tristán del Pozo; al final, para una magnífica vista de la ciudad, visitaremos los típicos distritos de Carmen alto y Yanahuara. (Mirador e Iglesia).'),(5427,743,'_descripcion','field_5e629af417021'),(5428,743,'galeria','a:3:{i:0;s:3:\"343\";i:1;s:3:\"344\";i:2;s:3:\"345\";}'),(5429,743,'_galeria','field_5e629b2417022'),(5430,743,'precio',''),(5431,743,'_precio','field_5e62a061a38d2'),(5432,743,'testimonio','4'),(5433,743,'_testimonio','field_5e62c2b421f51'),(5434,743,'incluye_iconos',''),(5435,743,'_incluye_iconos','field_645c284de7fdd'),(5436,66,'inline_featured_image','0'),(5437,66,'_yoast_wpseo_primary_category',''),(5439,745,'_edit_lock','1684950091:1'),(5440,745,'_edit_last','1'),(5441,745,'_oembed_c3156fcc2f91466f1f97b923c14707b1','{{unknown}}'),(5442,746,'_wp_attached_file','2023/05/4337187e-6122-41ec-ba50-ab639dbbddb8.jpeg'),(5443,746,'_wp_attachment_metadata','a:6:{s:5:\"width\";i:960;s:6:\"height\";i:1280;s:4:\"file\";s:49:\"2023/05/4337187e-6122-41ec-ba50-ab639dbbddb8.jpeg\";s:8:\"filesize\";i:345045;s:5:\"sizes\";a:6:{s:6:\"medium\