ógico de Pisac, pueblo colonial de Pisac,urubanba,centro arqueológico de ollantaytambo y chinchero','TOUR VALLE SAGRADO DE LOS INCAS','','inherit','closed','closed','','422-revision-v1','','','2023-05-05 21:51:45','2023-05-05 21:51:45','',422,'https://peruconexiontravel.local/?p=658',0,'revision','',0),(659,1,'2023-05-05 21:52:13','2023-05-05 21:52:13','','machu-picchu-100-years','','inherit','open','closed','','machu-picchu-100-years','','','2023-05-05 21:52:13','2023-05-05 21:52:13','',2,'https://peruconexiontravel.local/wp-content/uploads/2023/05/machu-picchu-100-years.svg',0,'attachment','image/svg+xml',0),(660,1,'2023-05-05 21:52:14','2023-05-05 21:52:14','','marca-peru','','inherit','open','closed','','marca-peru','','','2023-05-05 21:52:14','2023-05-05 21:52:14','',2,'https://peruconexiontravel.local/wp-content/uploads/2023/05/marca-peru.svg',0,'attachment','image/svg+xml',0),(661,1,'2023-05-05 21:52:15','2023-05-05 21:52:15','','min-cetur','','inherit','open','closed','','min-cetur','','','2023-05-05 21:52:15','2023-05-05 21:52:15','',2,'https://peruconexiontravel.local/wp-content/uploads/2023/05/min-cetur.svg',0,'attachment','image/svg+xml',0),(662,1,'2023-05-05 21:52:16','2023-05-05 21:52:16','','prom-peru','','inherit','open','closed','','prom-peru','','','2023-05-05 21:52:16','2023-05-05 21:52:16','',2,'https://peruconexiontravel.local/wp-content/uploads/2023/05/prom-peru.svg',0,'attachment','image/svg+xml',0),(663,1,'2023-05-05 21:52:16','2023-05-05 21:52:16','','safe-travels','','inherit','open','closed','','safe-travels','','','2023-05-05 21:52:16','2023-05-05 21:52:16','',2,'https://peruconexiontravel.local/wp-content/uploads/2023/05/safe-travels.svg',0,'attachment','image/svg+xml',0),(664,1,'2023-05-05 21:52:16','2023-05-05 21:52:16','','tripadvisor','','inherit','open','closed','','tripadvisor','','','2023-05-05 21:52:16','2023-05-05 21:52:16','',2,'https://peruconexiontravel.local/wp-content/uploads/2023/05/tripadvisor.svg',0,'attachment','image/s